using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        var items = new List<int> { 1, 2, 3 };

        var list = new PaginatedList<int>(items, 30, 2, 10);

        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(3, list.TotalPages);
        Assert.AreEqual(3, list.Count);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 1, 5);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("a", list[0]);
        Assert.AreEqual("b", list[1]);
        Assert.AreEqual("c", list[2]);
    }

    [TestMethod]
    public void TotalPages_CeilingDivision_RoundsUp()
    {
        var list = new PaginatedList<int>(new List<int>(), 11, 1, 10);

        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_NoRounding()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SinglePage()
    {
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 10);

        Assert.AreEqual(1, list.TotalPages);
    }

    [TestMethod]
    public void TotalPages_ZeroItems_IsZero()
    {
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        Assert.AreEqual(0, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FalseOnFirstPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_TrueOnSecondPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_TrueOnThirdPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 30, 3, 10);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_TrueWhenNotOnLastPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FalseOnLastPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FalseWhenSinglePage()
    {
        var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectFirstPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectMiddlePage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectLastPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItemPerPage()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 1);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(2, result[0]);
    }
}

