    public void ShowRequestId_FalseWhenRequestIdIsWhitespace()
    {
        var model = new ErrorViewModel { RequestId = "   " };

        // String.IsNullOrEmpty returns false for whitespace, so ShowRequestId is true
        Assert.IsTrue(model.ShowRequestId);
    }

