using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain the static queue to avoid cross-test contamination
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

        var notification = _service.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsNullWhenQueueIsEmpty()
    {
        var result = _service.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithDisplayName()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_WithDisplayName()
    {
        _service.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Course 'Math 101' has been updated", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_WithDisplayName()
    {
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Course", "101", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUser_IsSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _service.SendNotification("Student", "1", "Name", EntityOperation.CREATE, null);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CustomUserName_IsPreserved()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CreatedAtIsRecentTimestamp()
    {
        var before = DateTime.Now.AddSeconds(-2);

        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var after = DateTime.Now.AddSeconds(2);
        var notification = _service.ReceiveNotification();

        Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void SendAndReceive_MultipleDequeuedInFifoOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var n1 = _service.ReceiveNotification();
        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();
        var n4 = _service.ReceiveNotification();

        Assert.AreEqual("A", n1.EntityType);
        Assert.AreEqual("B", n2.EntityType);
        Assert.AreEqual("C", n3.EntityType);
        Assert.IsNull(n4);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
        _service.MarkAsRead(-1);
        // No assertion needed - just verify no exception is thrown
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var svc = new NotificationService();
        svc.Dispose();
        // No assertion needed - just verify no exception is thrown
    }

    [TestMethod]
    public void SendNotification_IsReadDefaultsFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_OperationToStringStoredCorrectly()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Student", "2", EntityOperation.UPDATE);
        _service.SendNotification("Student", "3", EntityOperation.DELETE);

        Assert.AreEqual("CREATE", _service.ReceiveNotification().Operation);
        Assert.AreEqual("UPDATE", _service.ReceiveNotification().Operation);
        Assert.AreEqual("DELETE", _service.ReceiveNotification().Operation);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_OverloadForwarding()
    {
        _service.SendNotification("Course", "2", "Calculus", EntityOperation.UPDATE, "User2");

        var n = _service.ReceiveNotification();

        Assert.IsNotNull(n);
        Assert.AreEqual("User2", n.CreatedBy);
        Assert.AreEqual("Course 'Calculus' has been updated", n.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "1", "", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }
}

