    public void About_ReturnsViewResult()
    {
        var result = _controller.About();

        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void About_WithStudents_ReturnsEnrollmentDateGroups()
    {
        _context.Students.Add(new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = new DateTime(2023, 9, 1) });
        _context.Students.Add(new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = new DateTime(2023, 9, 1) });
        _context.Students.Add(new Student { LastName = "Jones", FirstMidName = "Bob", EnrollmentDate = new DateTime(2024, 1, 15) });
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_CountsStudentsPerDate()
    {
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "X", EnrollmentDate = new DateTime(2023, 9, 1) });
        _context.Students.Add(new Student { LastName = "B", FirstMidName = "Y", EnrollmentDate = new DateTime(2023, 9, 1) });
