using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateContext();
        _controller = new StudentsController(_context);
        TestHelper.SetupController(_controller);
        SeedStudents();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2023, 9, 1) },
            new Student { FirstMidName = "Bob", LastName = "Baker", EnrollmentDate = new DateTime(2022, 1, 15) },
            new Student { FirstMidName = "Charlie", LastName = "Carson", EnrollmentDate = new DateTime(2024, 6, 1) }
        );
        _context.SaveChanges();
    }

    // ===== Index Tests =====

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
        Assert.AreEqual("Baker", model[1].LastName);
        Assert.AreEqual("Carson", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Carson", model[0].LastName);
        Assert.AreEqual("Baker", model[1].LastName);
        Assert.AreEqual("Anderson", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Baker", model[0].LastName);    // 2022
        Assert.AreEqual("Anderson", model[1].LastName); // 2023
        Assert.AreEqual("Carson", model[2].LastName);   // 2024
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Carson", model[0].LastName);   // 2024
        Assert.AreEqual("Anderson", model[1].LastName); // 2023
        Assert.AreEqual("Baker", model[2].LastName);    // 2022
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alice", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Baker", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Baker", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchNotFound_ReturnsEmptyResults()
    {
        var result = _controller.Index(null, null, "ZZZ", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_DefaultSort()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.AreEqual("name_desc", result.ViewData["NameSortParm"]);
        Assert.AreEqual("Date", result.ViewData["DateSortParm"]);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_NameDescSort()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // When sortOrder is "name_desc", NameSortParm becomes "" (default ascending)
        Assert.AreEqual("", result.ViewData["NameSortParm"]);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_DateSort()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // When sortOrder is "Date", DateSortParm toggles to "date_desc"
        Assert.AreEqual("date_desc", result.ViewData["DateSortParm"]);
    }

    [TestMethod]
    public void Index_WithCurrentFilter_MaintainsFilterWhenSearchIsNull()
    {
        var result = _controller.Index(null, "Alice", null, null) as ViewResult;

        Assert.AreEqual("Alice", result.ViewData["CurrentFilter"]);
        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Index_NewSearch_ResetsPageToFirst()
    {
        var result = _controller.Index(null, null, "Alice", 5) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_Pagination_ReturnsCorrectPage()
    {
        // Add more students to force pagination (pageSize is 10)
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"Student{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = new DateTime(2023, 1, 1)
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 2) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(2, model.PageIndex);
        Assert.IsTrue(model.HasPreviousPage);
    }

    // ===== Details Tests =====

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();

        var result = _controller.Details(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
        Assert.AreEqual(student.LastName, model.LastName);
        Assert.AreEqual(student.FirstMidName, model.FirstMidName);
    }

    // ===== Create GET Tests =====

    [TestMethod]
    public void Create_Get_ReturnsViewResult()
    {
        var result = _controller.Create();

        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void Create_Get_ReturnsStudentWithTodaysDate()
    {
        var result = _controller.Create() as ViewResult;

        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // ===== Create POST Tests =====

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Dave",
            LastName = "Davis",
            EnrollmentDate = new DateTime(2024, 1, 1)
        };

        var result = _controller.Create(student);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
