using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _mockEnv;
    private Mock<ILogger<CoursesController>> _mockLogger;
    private string _tempDir;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateContext();
        _tempDir = Path.Combine(Path.GetTempPath(), "ContosoTests_" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempDir);

        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _mockLogger = new Mock<ILogger<CoursesController>>();

        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        TestHelper.SetupController(_controller);

        SeedData();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Computer Science",
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1001, Title = "Intro to CS", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1002, Title = "Data Structures", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
    }

    // ===== Index Tests =====

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        var ctx = TestHelper.CreateContext();
        var controller = new CoursesController(ctx, _mockEnv.Object, _mockLogger.Object);
        TestHelper.SetupController(controller);

        var result = controller.Index() as ViewResult;
        var model = result.Model as List<Course>;

        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);

        controller.Dispose();
        ctx.Dispose();
    }

    // ===== Details Tests =====

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1001) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1001, model.CourseID);
        Assert.AreEqual("Intro to CS", model.Title);
    }

    [TestMethod]
    public void Details_IncludesDepartment()
    {
        var result = _controller.Details(1001) as ViewResult;

        var model = result.Model as Course;
        Assert.IsNotNull(model.Department);
        Assert.AreEqual("Computer Science", model.Department.Name);
    }

    // ===== Create GET Tests =====

    [TestMethod]
    public void Create_Get_ReturnsViewResult()
    {
        var result = _controller.Create();

        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void Create_Get_ReturnsNewCourse()
    {
        var result = _controller.Create() as ViewResult;

        var model = result.Model as Course;
        Assert.IsNotNull(model);
    }

    [TestMethod]
    public void Create_Get_SetsDepartmentSelectList()
    {
        _controller.Create();

        Assert.IsNotNull(_controller.ViewBag.DepartmentID);
    }

    // ===== Create POST Tests =====

    [TestMethod]
    public void Create_Post_ValidCourse_NoFile_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var result = _controller.Create(course, null);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidCourse_NoFile_SavesToDatabase()
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        _controller.Create(course, null);

        Assert.AreEqual(3, _context.Courses.Count());
        Assert.IsNotNull(_context.Courses.Find(2001));
    }

    [TestMethod]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.txt");
        mockFile.Setup(f => f.Length).Returns(1024L);

        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _controller.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("valid image file")));
    }

    [TestMethod]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.jpg");
        mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024L); // 6MB > 5MB limit

        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _controller.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("5MB")));
    }

    [TestMethod]
    public void Create_Post_ValidFileUpload_SavesFileAndRedirects()
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var content = new byte[] { 0xFF, 0xD8, 0xFF }; // minimal JPEG header
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("photo.jpg");
        mockFile.Setup(f => f.Length).Returns(content.Length);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
            .Callback<Stream>(target => target.Write(content, 0, content.Length));

        var result = _controller.Create(course, mockFile.Object);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);

        var savedCourse = _context.Courses.Find(2001);
        Assert.IsNotNull(savedCourse.TeachingMaterialImagePath);
        Assert.IsTrue(savedCourse.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 2001 };

        var result = _controller.Create(course, null) as ViewResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    [DataRow(".jpg")]
    [DataRow(".jpeg")]
    [DataRow(".png")]
    [DataRow(".gif")]
    [DataRow(".bmp")]
    public void Create_Post_AllowedFileExtensions_AreAccepted(string extension)
    {
        var course = new Course
        {
            CourseID = 3000 + extension.GetHashCode(),
            Title = "Test Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"test{extension}");
        mockFile.Setup(f => f.Length).Returns(100L);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, mockFile.Object);

        Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
    }

    [TestMethod]
    [DataRow(".pdf")]
    [DataRow(".doc")]
    [DataRow(".exe")]
    [DataRow(".txt")]
    public void Create_Post_DisallowedFileExtensions_AreRejected(string extension)
    {
        var course = new Course
        {
            CourseID = 2001,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"test{extension}");
        mockFile.Setup(f => f.Length).Returns(100L);

        var result = _controller.Create(course, mockFile.Object);

        Assert.IsInstanceOfType(result, typeof(ViewResult));
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // ===== Edit GET Tests =====

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit((int?)1001) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1001, model.CourseID);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit((int?)99999);

        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    // ===== Edit POST Tests =====

    [TestMethod]
    public void Edit_Post_ValidCourse_NoFile_RedirectsToIndex()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var seedCtx = TestHelper.CreateContext(dbName))
        {
            var dept = new Department { Name = "Test", Budget = 50000, StartDate = DateTime.Now };
            seedCtx.Departments.Add(dept);
            seedCtx.SaveChanges();
            seedCtx.Courses.Add(new Course { CourseID = 5001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID });
            seedCtx.SaveChanges();
        }

        using var actCtx = TestHelper.CreateContext(dbName);
        using var controller = new CoursesController(actCtx, _mockEnv.Object, _mockLogger.Object);
        TestHelper.SetupController(controller);

        var course = new Course
        {
            CourseID = 5001,
            Title = "Updated Course",
            Credits = 4,
            DepartmentID = actCtx.Departments.AsNoTracking().First().DepartmentID
        };

        var result = controller.Edit(course, null);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.pdf");
        mockFile.Setup(f => f.Length).Returns(1024L);

        var result = _controller.Edit(course, mockFile.Object) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Edit_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.png");
        mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024L); // 10MB > 5MB limit

        var result = _controller.Edit(course, mockFile.Object) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // ===== Delete GET Tests =====

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Delete(1001) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1001, model.CourseID);
    }

    // ===== DeleteConfirmed Tests =====

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        var initialCount = _context.Courses.Count();

        var result = _controller.DeleteConfirmed(1001);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Courses.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_CourseNoLongerInDatabase()
    {
        _controller.DeleteConfirmed(1001);

        Assert.IsNull(_context.Courses.Find(1001));
    }

    [TestMethod]
    public void DeleteConfirmed_WithImagePath_DeletesFileAndRedirects()
    {
        // Set up a course with an image path
        var course = _context.Courses.Find(1001);
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/old_image.jpg";
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(1001);

        var redirect = result as RedirectToActionResult;
