using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;
    private NotificationService _drainService;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateContext();
        _controller = new NotificationsController(_context);
        TestHelper.SetupController(_controller);

        // Drain the static queue to avoid cross-test contamination
        _drainService = new NotificationService();
        while (_drainService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        _drainService?.Dispose();
    }

    private static T GetAnonymousProperty<T>(object obj, string propertyName)
    {
        var prop = obj.GetType().GetProperty(propertyName);
        Assert.IsNotNull(prop, $"Property '{propertyName}' not found on {obj.GetType().Name}");
        return (T)prop.GetValue(obj);
    }

    // ===== GetNotifications Tests =====

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        Assert.IsTrue(GetAnonymousProperty<bool>(value, "success"));
        Assert.AreEqual(0, GetAnonymousProperty<int>(value, "count"));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Enqueue some notifications
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "2", "Math 101", EntityOperation.UPDATE, "Admin");

        var result = _controller.GetNotifications();

        var value = result.Value;
        Assert.IsTrue(GetAnonymousProperty<bool>(value, "success"));
        Assert.AreEqual(2, GetAnonymousProperty<int>(value, "count"));

        var notifications = GetAnonymousProperty<List<Notification>>(value, "notifications");
        Assert.AreEqual(2, notifications.Count);
        Assert.AreEqual("Student", notifications[0].EntityType);
        Assert.AreEqual("Course", notifications[1].EntityType);

        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var value = result.Value;
        Assert.IsTrue(GetAnonymousProperty<bool>(value, "success"));
        Assert.AreEqual(10, GetAnonymousProperty<int>(value, "count"));

        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_DequeuesNotifications()
    {
        var service = new NotificationService();
        service.SendNotification("Student", "1", EntityOperation.CREATE);

        // First call should return the notification
        var result1 = _controller.GetNotifications();
        Assert.AreEqual(1, GetAnonymousProperty<int>(result1.Value, "count"));

        // Second call should return empty (notification was dequeued)
        var result2 = _controller.GetNotifications();
        Assert.AreEqual(0, GetAnonymousProperty<int>(result2.Value, "count"));

        service.Dispose();
    }

    // ===== MarkAsRead Tests =====

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        Assert.IsTrue(GetAnonymousProperty<bool>(value, "success"));
    }

    [TestMethod]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        var result1 = _controller.MarkAsRead(999);
        var result2 = _controller.MarkAsRead(0);

        Assert.IsTrue(GetAnonymousProperty<bool>(result1.Value, "success"));
        Assert.IsTrue(GetAnonymousProperty<bool>(result2.Value, "success"));
    }

    // ===== Index Tests =====

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }
}

