+    // ===== Edit GET Tests =====
+
+    [TestMethod]
+    public void Edit_Get_NullId_ReturnsBadRequest()
+    {
+        var result = _controller.Edit((int?)null);
+
+        var statusResult = result as StatusCodeResult;
+        Assert.IsNotNull(statusResult);
+        Assert.AreEqual(400, statusResult.StatusCode);
+    }
+
+    [TestMethod]
+    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
+
+        var result = _controller.Edit((int?)instructor.ID) as ViewResult;
+
+        Assert.IsNotNull(result);
+        var model = result.Model as Instructor;
+        Assert.IsNotNull(model);
+        Assert.AreEqual(instructor.ID, model.ID);
+    }
+
+    [TestMethod]
+    public void Edit_Get_PopulatesAssignedCourseData()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
+
+        var result = _controller.Edit((int?)instructor.ID) as ViewResult;
+
+        var courses = result.ViewData["Courses"] as List<AssignedCourseData>;
+        Assert.IsNotNull(courses);
+        Assert.AreEqual(2, courses.Count);
+        // The assigned course should be marked
+        var assignedCourse = courses.First(c => c.CourseID == 101);
+        Assert.IsTrue(assignedCourse.Assigned);
+    }
+
+    [TestMethod]
+    public void Edit_Get_UnassignedCourseMarkedCorrectly()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
+
+        var result = _controller.Edit((int?)instructor.ID) as ViewResult;
+
+        var courses = result.ViewData["Courses"] as List<AssignedCourseData>;
+        var unassignedCourse = courses.First(c => c.CourseID == 102);
+        Assert.IsFalse(unassignedCourse.Assigned);
+    }
+
+    // ===== Delete GET Tests =====
+
+    [TestMethod]
+    public void Delete_Get_NullId_ReturnsBadRequest()
+    {
+        var result = _controller.Delete(null);
+
+        var statusResult = result as StatusCodeResult;
+        Assert.IsNotNull(statusResult);
+        Assert.AreEqual(400, statusResult.StatusCode);
+    }
+
+    [TestMethod]
+    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
+    {
+        var instructor = _context.Instructors.First();
+
+        var result = _controller.Delete(instructor.ID) as ViewResult;
+
+        Assert.IsNotNull(result);
+        var model = result.Model as Instructor;
+        Assert.IsNotNull(model);
+        Assert.AreEqual(instructor.ID, model.ID);
+    }
+
+    [TestMethod]
+    public void Delete_Get_InvalidId_ReturnsNotFound()
+    {
+        var result = _controller.Delete(99999);
+
+        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
+    }
+
+    // ===== DeleteConfirmed Tests =====
+
+    [TestMethod]
+    public void DeleteConfirmed_RemovesInstructorAndRedirects()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");
+        var initialCount = _context.Instructors.Count();
+
+        var result = _controller.DeleteConfirmed(instructor.ID);
+
+        var redirect = result as RedirectToActionResult;
+        Assert.IsNotNull(redirect);
+        Assert.AreEqual("Index", redirect.ActionName);
+        Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
+    }
+
+    [TestMethod]
+    public void DeleteConfirmed_ClearsDepartmentAdministratorReference()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
+        var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);
+        Assert.IsNotNull(dept.InstructorID); // verify instructor is admin
+
+        _controller.DeleteConfirmed(instructor.ID);
+
+        // Refresh from database
+        var updatedDept = _context.Departments.Find(dept.DepartmentID);
+        Assert.IsNull(updatedDept.InstructorID);
+    }
+
+    [TestMethod]
+    public void DeleteConfirmed_InstructorNoLongerInDatabase()
+    {
+        var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");
+        var instructorId = instructor.ID;
+
+        _controller.DeleteConfirmed(instructorId);
+
+        Assert.IsNull(_context.Instructors.Find(instructorId));
+    }
+}
